    ListNode next;
    ListNode(int x) {
        val = x;
    }
}
class Solution {
    public ListNode reverseLinkedList(ListNode data) {
        ListNode newHead = null;
        while (data != null) {
            ListNode newNode = new ListNode(data.val);
            newNode.next = newHead;
            newHead = newNode;
            data = data.next;
        }
        return newHead;
    }
}

