package main

type ListNode struct {
    Val  int
    Next *ListNode
}

func reverseLinkedList(data *ListNode) *ListNode {
    newHead := &ListNode{}
    for data != nil {
        newNode := &ListNode{Val: data.Val}
        newNode.Next = newHead.Next
        newHead.Next = newNode
        data = data.Next
    }
    return newHead.Next
}

